/* ===========================================================================
 * src/hardware/vga.c
 * =========================================================================*/
/* #include "vga.h" -- merged */
/* #include "player_config.h" -- merged */
/* #include "entity.h" -- merged */

/*Global pixel buffer pointer */
volatile int pixel_buffer_start; // global variable

/*Back buffers (for double buffer)*/
short int Buffer1[SCREEN_HEIGHT][BUFFER_WIDTH]; // 240 rows, 512 (320 + padding) columns
short int Buffer2[SCREEN_HEIGHT][BUFFER_WIDTH];

/* Helpers Functions*/
static void swap(int* a, int* b);

void vga_init(){
    volatile int *pixel_ctrl_ptr = (volatile int*) PIXEL_BUF_CTRL_BASE;

    *pixel_ctrl_ptr = 0; //clear just in case
    /* Set front buffer to Buffer1*/
    *(pixel_ctrl_ptr + 1) = (int)&Buffer1;

    wait_for_vsync();

    pixel_buffer_start = *pixel_ctrl_ptr;
    clear_screen();

    /*set back buffer to Buffer2*/
    *(pixel_ctrl_ptr + 1) = (int)&Buffer2;

    pixel_buffer_start = *(pixel_ctrl_ptr + 1);
    clear_screen();
}

void plot_pixel(int x, int y, short int colour) {
  //make sure we are drawing properly
  if(x < 0 || x >= SCREEN_WIDTH || y < 0 || y >= SCREEN_HEIGHT){
    return;
  }
  volatile short int* one_pixel_address;
  one_pixel_address = (volatile short int*)(pixel_buffer_start + (y << 10) + (x << 1));
  *one_pixel_address = colour;
}

void clear_screen() {
  for (int y = 0; y < SCREEN_HEIGHT; y++) {
    volatile short *row_ptr = (volatile short* )(pixel_buffer_start + (y << 10));

    for (int x = 0; x < SCREEN_WIDTH; x++) {
      row_ptr[x] = 0x0000;  // set to black
    }
  }
}

void fill_screen(short colour) {
    for (int y = 0; y < SCREEN_HEIGHT; y++) {
        volatile short *row = (volatile short *)(pixel_buffer_start + (y << 10));
        for (int x = 0; x < SCREEN_WIDTH; x++) row[x] = colour;
    }
}

void draw_rect(int x, int y, int width, int height, short colour){
    int x_end = x + width;
    int y_end = y + height;

    if (x < 0) x = 0;
    if (y < 0) y = 0;
    if (x_end > SCREEN_WIDTH) x_end = SCREEN_WIDTH;
    if (y_end > SCREEN_HEIGHT) y_end = SCREEN_HEIGHT;
    
    for(int row = y; row < y_end; row++){
        volatile short *row_ptr = (volatile short*)(pixel_buffer_start + (row << 10));
        for(int col = x ; col < x_end; col++){
            row_ptr[col] = colour;
        }
    }
}

void swap(int* a, int* b) {
  int temp = *a;
  *a = *b;
  *b = temp;
}

void draw_line(int x0, int y0, int x1, int y1, short int colour) {
  bool is_steep = abs(y1 - y0) > abs(x1 - x0);
  if (is_steep) {
    swap(&x0, &y0);
    swap(&x1, &y1);
  }
  if (x0 > x1) {
    swap(&x0, &x1);
    swap(&y0, &y1);
  }

  int deltax = x1 - x0;
  int deltay = abs(y1 - y0);
  int error = -(deltax / 2);
  int y = y0;
  int y_step = (y0 < y1) ? 1 : -1;

  for (int x = x0; x <= x1; x++) {
    if (is_steep) {
      plot_pixel(y, x, colour);
    } else {
      plot_pixel(x, y, colour);
    }
    error += deltay;
    if (error > 0) {
      y += y_step;
      error -= deltax;
    }
  }
}

void wait_for_vsync() {
    volatile int * pixel_ctrl_ptr = (int *)PIXEL_BUF_CTRL_BASE;
    *pixel_ctrl_ptr = 1;                  // request swap
    while (*(pixel_ctrl_ptr + 3) & 0x1);  // wait for S bit to go to
    pixel_buffer_start = *(pixel_ctrl_ptr + 1);//update start
}

void draw_rect_outline(int x, int y, int width, int height, short colour){
    int x_end = x + width - 1; // Subtract 1 to stay within the width/height
    int y_end = y + height - 1;

    // Boundary clipping
    if (x < 0) x = 0;
    if (y < 0) y = 0;
    if (x_end >= SCREEN_WIDTH) x_end = SCREEN_WIDTH - 1;
    if (y_end >= SCREEN_HEIGHT) y_end = SCREEN_HEIGHT - 1;
    
    for(int row = y; row <= y_end; row++){
        volatile short *row_ptr = (volatile short*)(pixel_buffer_start + (row << 10));
        for(int col = x; col <= x_end; col++){
            // Only draw if we are on one of the four edges
            if (row == y || row == y_end || col == x || col == x_end) {
                row_ptr[col] = colour;
            }
        }
    }
}


/* ===========================================================================
 * src/hardware/timer.c
 * =========================================================================*/
/* #include "timer.h" -- merged */
/* #include "address_map.h" -- merged */

#define FPS 60
#define TIMER_FREQ 100000000

volatile int frame_flag = 0;

volatile unsigned int *timer_ptr = (volatile unsigned int*)TIMER_BASE;

void timer_init(){
    // 60 - FPS -> 100MHz / 60
    unsigned int period =  TIMER_FREQ / FPS;
    timer_ptr[0] = 1; // Clear TO
    
    timer_ptr[1] = 0x8; // stop timer

    //load low bits
    timer_ptr[2] = period & 0xFFFF;
    
    //load high bits
    timer_ptr[3] = (period >> 16);

    asm volatile("csrs mie, %0" : : "r"(0x10000)); //enable IRQ16

    // turn on  CONT START and IRQ
    timer_ptr[1] = 0b111;
}

void timer_irq(){
   timer_ptr[0] = 1;
   frame_flag = 1;
}


/* ===========================================================================
 * src/hardware/keyboard.c
 * =========================================================================*/
/* #include "keyboard.h" -- merged */
/* #include "address_map.h" -- merged */

//pointer to base
volatile int *ps2 = (volatile int *)PS2_BASE;

/* Bitmask table â€” one bit per scancode (256 scancodes, 256/8 = 32 bytes) */
//there are 256 possible scancodes
unsigned char key_state[256 / 8];

void key_set(unsigned char code, int down) {
    if (down) key_state[code >> 3] |=  (1 << (code & 7)); //set to 1 if its pressed
    else      key_state[code >> 3] &= ~(1 << (code & 7)); //set to 0 if released
}

int key_pressed(unsigned char scancode) {
    return (key_state[scancode  >> 3] >> (scancode & 7)) & 1;
}

void keyboard_update(void) {
    static int break_next = 0; //next byte is a break (key-up) code 
    static int extended   = 0; //previous byte was 0xE0 prefix 

    int raw; //read once - bit 15 (RVALID)
    while ((raw = ps2[0]) & 0x8000) { //check bit 15 (RVALID), if 0 FIFO is empty
        unsigned char byte = (unsigned char)(raw & 0xFF); //take last 8 bits (the actual data)

        if (byte == 0xE0) { //warns its an exteneded key 
            extended = 1;
        } else if (byte == 0xF0) { // not a key, means its a key up event
            break_next = 1;
        } else {
            /* Extended keys (arrows etc.) use 0xE0 prefix â€” store them
               with bit 7 set so they don't collide with normal scancodes.
               e.g. arrow up: raw=0x75, stored as 0xF5 when extended.    */
            unsigned char code = extended ? (byte | 0x80) : byte;
            key_set(code, !break_next);
            break_next = 0;
            extended   = 0;
        }
    }
}


/* ===========================================================================
 * src/hardware/audio.c
 * =========================================================================*/
/* #include "audio.h" -- merged */
/* #include "address_map.h" -- merged */

SoundInstance active_sounds[MAX_ACTIVE_SOUNDS];
const int *bgm_data = NULL;
int bgm_pos = 0;
int bgm_len = 0;

void audio_update(){
    struct audio_t* audio_ptr = ((struct audio_t*) AUDIO_BASE);

    while(audio_ptr->wsrc > 0 && audio_ptr->wslc > 0){
        volatile int dummy_l = audio_ptr->ldata;
        volatile int dummy_r = audio_ptr->rdata;
        (void)dummy_l; (void)dummy_r;

        long long mixed_sample = 0;

        if(bgm_data != NULL){
            mixed_sample += bgm_data[bgm_pos];
            if(++bgm_pos >= bgm_len) bgm_pos = 0;
        }

        for(int i = 0; i < MAX_ACTIVE_SOUNDS; i++){
            if(active_sounds[i].active){
                mixed_sample += (long long)(active_sounds[i].samples[active_sounds[i].position] * active_sounds[i].volume);
                if(++active_sounds[i].position >= active_sounds[i].length){
                    if(active_sounds[i].loop) active_sounds[i].position = 0;
                    else active_sounds[i].active = 0;
                }
            }
        }

        // Clip to 32-bit range
        if(mixed_sample >  2147483647LL) mixed_sample =  2147483647LL;
        if(mixed_sample < -2147483648LL) mixed_sample = -2147483648LL;

        audio_ptr->ldata = (int)mixed_sample;
        audio_ptr->rdata = (int)mixed_sample;
    }
}

void play_bgm(const int *data, int length){
    bgm_data = data;
    bgm_len = length;
    bgm_pos = 0;
}

void play_sfx(const int *data, int length, float volume, int loop){
    for(int i = 0; i < MAX_ACTIVE_SOUNDS; i++){
        if (!active_sounds[i].active) {
            active_sounds[i].samples = data;
            active_sounds[i].length = length;
            active_sounds[i].position = 0;
            active_sounds[i].volume = volume;
            active_sounds[i].active = 1;
            active_sounds[i].loop = loop;
            return;
        }
    }
}


